  },
  badge: {
    display: 'inline-block',
    marginLeft: 6,
    padding: '1px 6px',
    borderRadius: 4,
    background: '#ff9800',
    color: '#fff',
    fontSize: 10,
    fontWeight: 700,
  },
  actions: {
    display: 'flex',
    gap: 6,
  },
  btn: {
    padding: '4px 10px',
    borderRadius: 4,
    border: '1px solid #ccc',
    background: '#fff',
    cursor: 'pointer',
    fontSize: 12,
  },
  btnReset: {
    borderColor: '#ff5722',
