import { chromium } from 'playwright';

const browser = await chromium.launch({ headless: true });
const page = await browser.newPage({ viewport: { width: 1400, height: 900 } });

// Navigate to VoucherDemo Form story
await page.goto('http://localhost:6006', {
  waitUntil: 'networkidle',
  timeout: 30000,
});

await page.waitForTimeout(2000);

// Click on SDUI > VoucherDemo in sidebar
const voucherDemo = page.locator('button:has-text("VoucherDemo")').first();
if (await voucherDemo.isVisible()) {
  await voucherDemo.click();
  await page.waitForTimeout(500);
}

// Click on Form story
const formStory = page.locator('[data-item-id*="voucher"][data-item-id*="form" i]').first();
if (await formStory.isVisible()) {
  await formStory.click();
  await page.waitForTimeout(2000);
} else {
  // Try clicking directly in the sidebar tree
  const sduiSection = page.locator('button:has-text("SDUI")').first();
  if (await sduiSection.isVisible()) {
    await sduiSection.click();
    await page.waitForTimeout(500);
  }
}

await page.waitForTimeout(2000);
await page.screenshot({
  path: '.storybook/screenshots/codemirror-editor.png',
  fullPage: false,
});

console.log('Screenshot 1 saved');

// Also try navigating directly with a story click
const allLinks = await page.locator('[data-item-id]').all();
const ids = [];
for (const link of allLinks.slice(0, 30)) {
  const id = await link.getAttribute('data-item-id');
  ids.push(id);
}
console.log('Story IDs found:', ids.join(', '));

await browser.close();

