  fullPage: false,
});

console.log('Screenshot 1 saved');

// Also try navigating directly with a story click
const allLinks = await page.locator('[data-item-id]').all();
const ids = [];
for (const link of allLinks.slice(0, 30)) {
  const id = await link.getAttribute('data-item-id');
  ids.push(id);
}
console.log('Story IDs found:', ids.join(', '));

await browser.close();

