import { chromium } from 'playwright';

const browser = await chromium.launch({ headless: true });
const page = await browser.newPage({ viewport: { width: 1800, height: 1000 } });

await page.goto('http://localhost:6006/?path=/story/sdui-voucherdemo--form', {
  waitUntil: 'networkidle',
  timeout: 30000,
});

await page.waitForTimeout(4000);

// Full page screenshot
await page.screenshot({
  path: '.storybook/screenshots/codemirror-editor-full.png',
  fullPage: false,
});

// Crop just the editor panel area
const panel = page.locator('.cm-editor').first();
if (await panel.isVisible()) {
  await panel.screenshot({
    path: '.storybook/screenshots/codemirror-editor-panel.png',
  });
  console.log('Panel screenshot saved');
}

console.log('Full screenshot saved');

await browser.close();

